      "content": "const problemsData = require('../../data/problems.json');

function getDifficultyRange(difficulty) {
  switch (difficulty) {
    case 'easy':
      return { min: 0, max: 1200 };
    case 'medium':
      return { min: 1201, max: 2200 };
    case 'hard':
      return { min: 2201, max: Infinity };
    default:
      return { min: 0, max: Infinity };
  }
}

function countDifficultyBreakdown(problems) {
  const breakdown = { easy: 0, medium: 0, hard: 0 };
  problems.forEach(p => {
    if (p.difficulty <= 1200) breakdown.easy++;
    else if (p.difficulty <= 2200) breakdown.medium++;
    else breakdown.hard++;
  });
  return breakdown;
}

function uniqueSorted(arr) {
  return Array.from(new Set(arr)).sort();
}

async function listProblems({ difficulty, includeComponents }) {
  // Filter by difficulty
  const { min, max } = getDifficultyRange(difficulty);
  let filtered = problemsData.filter(p => p.difficulty >= min && p.difficulty <= max);

  // Sort by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => a.roundId - b.roundId);

  // Enforce paging limit 50
  const appliedLimit = 50;
  const limited = filtered.slice(0, appliedLimit);

  // Compose difficulty breakdown on filtered set (before limit)
  const difficultyBreakdown = countDifficultyBreakdown(filtered);

  // Compose componentLanguages if requested
  let componentLanguages = [];
  if (includeComponents) {
    const langs = [];
    limited.forEach(p => {
      if (Array.isArray(p.componentLanguages)) {
        langs.push(...p.componentLanguages);
      }
    });
    componentLanguages = uniqueSorted(langs);
  }

  return {
    problems: limited,
    totalProblems: problemsData.length,
    filteredCount: filtered.length,
    appliedLimit,
    difficultyBreakdown,
    componentLanguages
  };
}

module.exports = {
  listProblems
};
