async function getProblems(req, res) {
  try {
    const difficulty = req.query.difficulty || '';
    const includeComponents = req.query.includeComponents === 'true';

    const result = await listProblems({ difficulty, includeComponents });

    res.json({
      problems: result.problems,
      totalProblems: result.totalProblems,
      filteredCount: result.filteredCount,
      appliedLimit: result.appliedLimit,
      difficultyBreakdown: result.difficultyBreakdown,
      componentLanguages: result.componentLanguages
    });
  } catch (err) {
    res.status(500).json({ error: 'Internal server error' });
  }
}
